// Status-based batch selection (replaces the single-row picker).
// Reads all CSV leads + the tracker sheet, skips leads already drafted,
// and emits up to `batch_size` fresh leads — one item each — for the loop.
const csvRows = $('Parse CSV').all().map(i => i.json);
if (!csvRows.length) {
  throw new Error('CSV produced no rows. Check lead_csv_path / the mounted leads.csv.');
}
const cfg = $('Config').first().json;

// Pause switch: emit nothing so the loop is a clean no-op.
const paused = cfg.paused === true || String(cfg.paused).toLowerCase() === 'true';
if (paused) return [];

const batchSize = Math.max(1, Number(cfg.batch_size || 10));

// "Already done" = tracker rows whose status is Draft_Created.
// The tracker sheet uses lowercase headers (email, status, ...).
let trackerRows = [];
try { trackerRows = $('Read Tracker Sheet').all().map(i => i.json); } catch (e) { trackerRows = []; }
const done = new Set(
  trackerRows
    .filter(r => String(r.status || '').trim() === 'Draft_Created')
    .map(r => String(r.email || '').trim().toLowerCase())
    .filter(Boolean)
);

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const runId = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

const seen = new Set();
const out = [];
for (const row of csvRows) {
  const email = String(row.email || '').trim();
  if (!email) continue;
  const key = email.toLowerCase();
  if (done.has(key) || seen.has(key)) continue; // skip processed + duplicates
  seen.add(key);

  const lead = {
    ...row,
    name: row.fullName || [row.firstName, row.lastName].filter(Boolean).join(' ').trim() || email,
    title: row.position || '',
    organization_name: row.organizationName || row.company || 'Unknown Company',
    email,
    organization_industry: row.organizationIndustry || '',
    organization_size: row.organizationSize || '',
    organization_founded_year: row.organizationFoundedYear || '',
    organization_description: row.organizationDescription || '',
    organization_specialities: row.organizationSpecialities || '',
    organization_website: row.organizationWebsite || '',
    organization_linkedin: row.organizationLinkedinUrl || '',
    linkedin_url: row.linkedinUrl || '',
    seniority: row.seniority || '',
    functional: row.functional || '',
    phone_numbers: row.phone_numbers || '',
    all_emails: row.all_emails || '',
    city: row.city || row.organizationCity || '',
    state: row.state || row.organizationState || '',
    country: row.country || row.organizationCountry || '',
  };

  out.push({ json: {
    run_id: runId,
    grok_worker_url: cfg[(cfg.ai_provider || 'chatgpt') + '_worker_url'] || cfg.chatgpt_worker_url || 'http://host.docker.internal:8787',
    status: 'Fetched',
    operator_action: `Batch lead ${out.length + 1}/${batchSize}.`,
    updated_at: new Date().toISOString(),
    lead,
    raw_apollo_json: JSON.stringify(lead),
    idempotency_key: `${key}_${(lead.organization_name || '').toLowerCase().replace(/[^a-z0-9]+/g, '_')}_${runId.slice(0, 8)}`,
  } });

  if (out.length >= batchSize) break;
}

if (!out.length) {
  // Nothing left to do — surface a clear, non-fatal marker row count of 0.
  return [];
}
return out;

// Turn Grok's Stage 3 output into clean Gmail fields.
// Stage 3 emits: "To: ...\nSubject: ...\n\n<body>\n\nBest,\nSender Name".
// We extract the subject, strip the To:/Subject: header block and Grok's
// placeholder sign-off, then append the operator's own signature.
const a3 = $('Adopt Stage 3 Context').item.json;
const cfg = $('Config').first().json;
const lead = a3.lead || {};
const raw = (a3.stage3 && a3.stage3.responseText) ? String(a3.stage3.responseText) : '';

// Subject line
const subjMatch = raw.match(/^\s*Subject:\s*(.+)$/m);
const subject = subjMatch ? subjMatch[1].trim() : '';

// Body: everything after the Subject line's following blank line; else strip a
// stray leading "To:" line.
let body;
if (subjMatch) {
  const idx = raw.indexOf(subjMatch[0]) + subjMatch[0].length;
  body = raw.slice(idx).replace(/^\s*\n/, '').replace(/^\s+/, '');
} else {
  body = raw.replace(/^\s*To:.*$/m, '').replace(/^\s+/, '');
}

// Remove Grok's trailing sign-off ("Best," and an optional name line) so we can
// append our own signature consistently.
body = body.replace(/\n+\s*Best,?\s*(\n[^\n]*)?\s*$/i, '').replace(/\s+$/, '');

const signature = String(cfg.email_signature || '').trim();
const email_body = signature ? `${body}\n\n${signature}` : body;
const fallbackSubject = 'Quick question about ' + (lead.organization_name || 'your company');

return [{ json: {
  ...a3,
  email_subject: subject || fallbackSubject,
  email_body,
  recipient: lead.email || '',
} }];

// End-of-batch honesty check. Continue-on-error keeps the batch running past a
// bad lead, but the execution would otherwise show green even if no draft was
// made. Here we tally this run's outcomes from the tracker sheet and throw if
// any lead didn't end as Draft_Created, so the run finishes RED with a count.
const runId = $('Select Batch').first().json.run_id;
const expected = $('Select Batch').all().length;

let rows = [];
try { rows = $('Read Batch Result').all().map(i => i.json); }
catch (e) { rows = $input.all().map(i => i.json); }

const mine = rows.filter(r => String(r.run_id || '') === String(runId));
const drafted = mine.filter(r => String(r.status || '') === 'Draft_Created').length;
const failed = mine.filter(r => String(r.status || '') === 'Failed').length;
const summary = `Batch ${runId}: ${drafted} drafted, ${failed} failed (of ${expected} leads).`;

if (drafted < expected) {
  throw new Error(
    summary + ' Not every lead produced a draft — see the tracker sheet ' +
    '(status != Draft_Created). Those leads are retried automatically next run.'
  );
}

return [{ json: { run_id: runId, expected, drafted, failed, summary } }];

// Merge every file read from the attachments folder into ONE item (so one email
// gets all of them), carrying the Format Email fields. Each input item is one
// file with binary under 'data'; we re-key them attachment_0, attachment_1, ...
// If the folder was empty, Read Attachment still emits one (empty) item via
// alwaysOutputData, so count stays 0 and the draft is sent without attachments.
const items = $input.all();
const fe = $('Format Email').item.json;

const binary = {};
let count = 0;
for (const it of items) {
  if (it.binary) {
    for (const key of Object.keys(it.binary)) {
      binary['attachment_' + count] = it.binary[key];
      count++;
    }
  }
}

const out = { json: { ...fe, attachment_count: count } };
if (count > 0) out.binary = binary;
return [out];
